const state = {
  submitting: false,
  lastError: ''
};

function login() {
  state.submitting = true;
  const idValue = document.getElementById('idInput').value.trim();
  const pwValue = document.getElementById('pwInput').value.trim();

  if (!idValue || !pwValue) {
    showAlert('아이디와 비밀번호를 입력하세요.');
    state.submitting = false;
    return false;
  }

  return true;
}

function showAlert(message) {
  state.lastError = message;
  window.alert(message);
}

function bindEvents() {
  document.getElementById('loginBtn').addEventListener('click', function() {
    login();
  });
}

bindEvents();

public List<Map<String, Object>> findPartners(Map<String, Object> param) {
    return dao.selectPartnerList(param);
}

public Map<String, Object> getNoticeDetail(Long noticeId) {
    Map<String, Object> result = new HashMap<>();
    NoticeDto dto = noticeDao.selectDetail(noticeId);

    result.put("title", dto.getTitle());
    result.put("body", dto.getBody());
    return result;
}

public Map<String, Object> detail(Long noticeId) {
    Map<String, Object> response = new HashMap<>();
    response.put("status", "ok");
    response.put("data", noticeService.getNoticeDetail(noticeId));
    return response;
}

public class NoticeDto {
    private String title;
    private String body;
}
